package com.google.gson.protobuf.generated;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.protobuf.Descriptors;
import com.google.protobuf.DescriptorProtos;
import com.google.protobuf.ExtensionRegistry;
import com.google.protobuf.ExtensionRegistryLite;
import com.google.protobuf.GeneratedMessage;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

class AnnotationsTest {

  private ExtensionRegistryLite mockRegistryLite;
  private ExtensionRegistry mockRegistry;

  @BeforeEach
  void setUp() {
    mockRegistryLite = mock(ExtensionRegistryLite.class);
    mockRegistry = mock(ExtensionRegistry.class);
  }

  @Test
  void testRegisterAllExtensions_WithExtensionRegistryLite() {
    // Call the static method
    Annotations.registerAllExtensions(mockRegistryLite);

    // No exceptions and no interactions expected with mockRegistryLite (method is likely empty)
    verifyNoInteractions(mockRegistryLite);
  }

  @Test
  void testRegisterAllExtensions_WithExtensionRegistry() {
    // Call the static method
    Annotations.registerAllExtensions(mockRegistry);

    // No exceptions and no interactions expected with mockRegistry (method is likely empty)
    verifyNoInteractions(mockRegistry);
  }

  @Test
  void testGetDescriptor_NotNull() {
    Descriptors.FileDescriptor descriptor = Annotations.getDescriptor();
    assertNotNull(descriptor);
  }

  @Test
  void testSerializedNameAndSerializedValueFields() {
    assertNotNull(Annotations.serializedName);
    assertEquals(String.class, Annotations.serializedName.getExtensionType());

    assertNotNull(Annotations.serializedValue);
    assertEquals(String.class, Annotations.serializedValue.getExtensionType());

    assertEquals(Annotations.SERIALIZED_NAME_FIELD_NUMBER, 92066888);
    assertEquals(Annotations.SERIALIZED_VALUE_FIELD_NUMBER, 92066888);
  }

  @Test
  void testPrivateConstructor() throws NoSuchMethodException, IllegalAccessException, InvocationTargetException, InstantiationException {
    var constructor = Annotations.class.getDeclaredConstructor();
    constructor.setAccessible(true);
    // Instantiate to cover private constructor
    Object instance = constructor.newInstance();
    assertNotNull(instance);
    assertTrue(instance instanceof Annotations);
  }
}
